var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"저, 저기 봐! 구원 기사단이 있는 곳으로 괴수들이 몰려들고 있어!","JPN":"あ、あれを見ろ！　救世騎士団のところに怪獣が集まっている！","ENG":"L-look! The monsters are rushing towards the Knights of Redemption!","TWN":"看，看那邊！怪獸正在湧向救贖騎士團那裡！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"어마어마하게 많아……! 저 많은 수를 어떻게 감당하는 거지?","JPN":"なんて数だ……！　あれをどう相手するっていうんだ？","ENG":"The numbers are huge...! How are they going to deal with all of them?","TWN":"太，太多了……！要怎麼對付那麼多怪獸啊？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"좌익이 앞서고 있다! 대열을 유지하도록!","JPN":"左翼が前に出すぎだ！　隊列を維持しろ！","ENG":"Left wing! Keep to your positions!","TWN":"左翼打頭陣！保持隊形！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"작전의 성공을 위해선 반드시 양익의 전력을 보존해야 한다!","JPN":"作戦成功のためには、必ず両翼の戦力を保たねばならない！","ENG":"We must equally preserve forces on both wings to make this plan work!","TWN":"為了作戰成功，必須保存二翼的戰鬥力！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"조심해, 알렌!","JPN":"気を付けて、アレン！","ENG":"Allen, watch out!","TWN":"小心，艾倫！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"비행형 괴수로군. 어느 틈에 여기까지…….","JPN":"飛行型の怪獣か、いつの間にここまで……","ENG":"A flying monster? When did it...","TWN":"是飛行類怪獸。什麼時候……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_HOWLING_02"},{"id":"L12_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"방금은 아슬아슬했어. 지휘도 집중하는 것도 좋지만 주위에도 신경 써 줘.","JPN":"今のは危なかったよ。指揮も大事だけど、周りにも気を配って。","ENG":"That was close. Focusing on your job is good, but don’t forget to look out for yourself.","TWN":"剛才很驚險。集中注意力指揮固然好，但也要注意周圍。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"새겨 듣지. 대신 요격해 줘서 고맙다.","JPN":"肝に銘じよう。代わりに倒してくれて感謝する。","ENG":"I'll keep that in mind. Thank you for the backup.","TWN":"我會銘記在心的，謝謝你……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"전하, 남서쪽 방향에서 비행형 괴수들이 다수 접근 중입니다.","JPN":"殿下、南西側から飛行型の怪獣が多数接近中です。","ENG":"Your Highness, multiple flying monsters are approaching from the Southwest direction.","TWN":"殿下，西南方向有多隻飛行類怪獸正在靠近。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"흠. 예상대로 저항이 거센가. 이 기회에 끝장을 내겠다는 심산이로군.","JPN":"ふむ。予想通りの激しい抵抗だ。ここで片を付けるつもりか。","ENG":"Hmm. Resistance is strong, as presumed. It seems like they're going to end things here for good.","TWN":"嗯，反抗和預想的一樣激烈嗎。看來是想借此機會做個了斷啊。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"사제들도 전부 탈진 직전입니다.","JPN":"司祭たちも疲れ果てています。","ENG":"The priests are exhausted.","TWN":"祭司也全都快虛脫了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"부상자들을 더 돌보기에는 손이 부족해요.","JPN":"これ以上負傷者が出れば、手が足りなくなります。","ENG":"There's not enough manpower to take care of casualties.","TWN":"照顧傷患的人手也不夠。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"샬롯, 적의 동향이 추가로 감지되진 않았나?","JPN":"シャーロット、敵の動きに進展は？","ENG":"Carlota, any more signs of the enemy?","TWN":"夏洛特，後續有發現敵人的動向嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"정찰병들의 보고에 따르면 방금 증원이 이 일대에 있는 마지막 전력입니다.","JPN":"偵察兵の報告によると、先の増援がここら一帯の最後の戦力だったようです。","ENG":"Scout reports show that the recent wave of enemies were the last forces in the area.","TWN":"根據偵察兵的報告，剛才的增援是這一帶最後的戰鬥力。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그렇겠지. 저것들에게 구원 기사단은 눈엣가시 같은 존재였으니 말이다.","JPN":"やはりな。奴らにとって救世騎士団は最も厄介な存在だ。","ENG":"I assume so. The Knights of Redemption would be a pain for them.","TWN":"我想也是。對於他們來說，救贖騎士團就是眼中釘一般的存在。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"이만하면 그대의 구상대로 적들을 모두 끌어낸 것 같군. 안 그런가, 알렌 경?","JPN":"おおむね構想通り、敵を引っ張り出すことには成功したのではないか？　どうだ、アレン？","ENG":"It looks like we drew out all of their forces, just like you planned. Isn't that right, Sir Allen?","TWN":"這樣算是按照你的設想，把敵人全都吸引過來了是嗎，艾倫卿？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"예. 저희를 노리기 위해 병력이 저렇게 밀집되었으니, 이제 와서 이탈하기도 어려울 겁니다.","JPN":"はい、私たちを狙うための兵力があれほど密集していれば、もはや離脱もままならないでしょう。","ENG":"Yes, Your Highness. It won't be easy for them to back out now, as they were all gathered to take us down.","TWN":"沒錯，如此密集的兵力對我們虎視眈眈，事到如今，我們恐怕很難逃脫。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"좋다! 좌익과 우익에 신호를 보내라! 중앙의 적을 섬멸하는 데 가세하도록!","JPN":"よし！　左翼と右翼に合図を送れ！　中央の敵の殲滅に加勢させろ！","ENG":"Good! Send the signal to both wings! Focus on eliminating the enemies in the center!","TWN":"很好！給左翼和右翼發訊號！讓他們幫忙殲滅中央的敵人！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"후방에서 대기 중이던 비공정과 전쟁 골렘들도 모두 동원한다.","JPN":"後方で待機している飛行艇とウォーゴーレムも一斉に動員する。","ENG":"Take the combat golems and the aircraft on standby.","TWN":"讓後方待命的飛空艇和戰爭泥人全部出動吧。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"이제 저희가 반격할 때로군요! 알겠습니다!","JPN":"我々が反撃する番ですね！　了解しました！","ENG":"This must be our time to fight back! Yes, sir!","TWN":"明白！現在輪到我們反擊了！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L36_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"저건……!","JPN":"あれは……！","ENG":"That's...!","TWN":"那是……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"마르티네즈의 깃발이 휘날린다! 전군, 진격하라!","JPN":"マルチネスの旗だ！　全軍、突撃しろ！","ENG":"The flag of Martinez is up! All forces, charge!","TWN":"馬汀尼茲的旗幟在揮舞！全軍，進擊！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"구원자님과 함께 싸우자!","JPN":"救世主様と共に戦うんだ！","ENG":"Fight alongside the Savior!","TWN":"與救贖者大人一同戰鬥！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"승리가 눈앞에 있다!! 구원이 눈앞에 있다!","JPN":"勝利が目の前だ！！　救いはもうすぐだ！","ENG":"Victory awaits! Salvation awaits!","TWN":"勝利就在眼前！！救贖就在眼前！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"평민, 우물쭈물거리다가 다른 병사들에게 공을 양보할 생각은 아니겠지?","JPN":"平民、ぐずぐずして他の兵士たちに手柄を渡すつもりではないだろうな？","ENG":"I hope you're not planning to just stand there and pass the glory to the others, peasant.","TWN":"平民，你不會是想一直磨蹭下去，把功勞全都讓給其他士兵吧？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"거인족들에게 밟히기 싫으면 눈에 띄는 활약을 보여 줘야 할 거다.","JPN":"巨人族に踏み付けられたくなければ、目覚ましい活躍をしてみせろ。","ENG":"Unless you want to get trampled by giants, you’d better show some action.","TWN":"不想被巨人族踩扁的話，你就該有引人注目的活躍表現。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"앗…… 네! 함께 싸우겠습니다, 전하!","JPN":"あっ……はい！　共に戦います、殿下！","ENG":"Oh... Yes, of course! I will fight with them, Your Highness!","TWN":"啊……是！我會一同戰鬥，殿下！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"후우……","JPN":"ふぅ……","ENG":"*Sigh*...","TWN":"呼……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"괜찮으십니까, 전하. 도주한 적들은 기마대가 추격 중입니다.","JPN":"ご無事であられますか、殿下。逃走した敵は騎馬隊が追いかけております。","ENG":"Everything fine, Your Highness? The chivalry is tracking down the fleeing enemies.","TWN":"您沒事吧，殿下。騎兵隊正在追擊逃走的敵人。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"계획대로 풀려서 다행이군. 마왕의 동태는 어떤가?","JPN":"幸い計画は想定通りに進んでいるようだな。魔王の動きは？","ENG":"I'm glad that things worked out according to plan. Any updates with the Demon Lord?","TWN":"計畫很順利啊，魔王的動向如何？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"정찰병들에게서는 아직 소식이 없습니다.","JPN":"偵察兵からはまだ何も。","ENG":"No additional scout reports, I'm afraid.","TWN":"偵察兵那邊還沒有消息。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"혹시…… 우리가 싸우는 동안 마왕도 도망치지 않았을까?","JPN":"もしかして……僕たちが戦っている間に魔王も逃げたんじゃないかな？","ENG":"What if... the Demon Lord fled while we were fighting?","TWN":"莫非……在我們衝鋒的時候魔王逃走了？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"결국에는 계획이 실패한 셈이니까.","JPN":"結局、計画は失敗したようなものだから。","ENG":"That's a plan fail.","TWN":"最終計畫還是失敗了嗎……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"아니. 그럴 리 없다.","JPN":"いや、そんなはずはない。","ENG":"No. There is no way.","TWN":"不，不可能。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"사파이어 프리즌이 계속 반응하고 있어. 괴수들과 다른 강렬한 독기를 감지했다는 증거야.","JPN":"サファイアプリズンが反応し続けている。怪獣とは別の強烈な毒気を感知している証拠だ。","ENG":"The Sapphire Prison is reacting nonstop. It means that it's sensing powerful poison that's different from the other monsters.","TWN":"藍寶稜鏡還有反應。這是檢測到了與怪獸不同的濃烈毒氣的證據。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"구원의 지팡이도 마찬가지예요.","JPN":"復活の杖も同じです。","ENG":"It's the same with the Staff of Resurrection.","TWN":"復活之杖也一樣。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"마왕의 심복들은 펜릴 용병단과 함께 모두 쓰러뜨렸으니……. 남은 건 하나뿐이겠죠.","JPN":"魔王の側近たちはフェンリル傭兵隊と私たちで全滅させましたから……残るは奴だけです。","ENG":"We have taken down all of the Demon Lord's henchmen with Fenrir Mercenaries... Which would leave us with only one remaining enemy.","TWN":"那些心腹已經全部被我們和芬里爾傭兵隊一起打倒了……應該就只剩下魔王了吧。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"어째서……?","JPN":"どうして……？","ENG":"Why...?","TWN":"為什麼……？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"부하들을 이렇게 허망하게 희생시켜 놓고도 멈추지 않는다니, 역시 이상해.","JPN":"部下をここまで無駄に失っても止まらないなんて、やっぱり変だ。","ENG":"After sacrificing all of his soldiers like this, he still won't stop... I don't understand.","TWN":"即使讓部下白白犧牲也不願意停下，我不能理解。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"그렇게까지 해서 세상을 멸망시켜야 할 이유가 대체 뭐야……?","JPN":"そうまでして世界を滅ぼしたい理由は何なんだ……？","ENG":"Why would he want to put an end to this world so bad...?","TWN":"哪怕如此也要毀滅世界的理由究竟是什麼呢……？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"어……?","JPN":"あ……？","ENG":"Huh...?","TWN":"呃……？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"평민, 너도 방금 느낀 건가?","JPN":"平民、貴様も感じたか。","ENG":"Did you feel it too, peasant?","TWN":"平民，你剛才也感覺到了嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"네. 뭔가……. 굉장히 섬뜩한 느낌이…….","JPN":"はい、何か……とても不気味な感じが……","ENG":"Yes. I felt something... incredibly sinister.","TWN":"是的，有種……毛骨悚然的感覺……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_QM","text":{"KOREA":"흠…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"뭐, 뭐지? 저 거인은……?","JPN":"な、なんだ？　あの巨人は……？","ENG":"W-what is that giant...?","TWN":"那，那個巨人，是什麼……？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"모, 모르겠어. 하지만 절대 평범한 인간은 아니야.","JPN":"わ、わからない。でも決して普通の人間ではない。","ENG":"I-I don't know. But that is not an ordinary man we're looking at.","TWN":"不，不知道。不過絕對不是一般人。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"이봐! 지금 당장 무기를 버려라! 그렇지 않다면 목숨을……!","JPN":"おい！　直ちに武器を捨てろ！　さもなくば命の保証は……！","ENG":"You there! Drop your weapon immediately! If not, we will–","TWN":"喂！現在馬上放下武器！否則……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"구원자님! 전하! 큰일입니다!","JPN":"救世主様！　殿下！　大変です！","ENG":"Savior! Your Highness! This is an emergency!","TWN":"救贖者大人！殿下！大事不好了！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L37_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그대는……? 우익의 6번대 대장 아닌가?","JPN":"そなたは……？　右翼六番隊の隊長ではないか？","ENG":"You... Aren't you the captain of the 6th Squad in the right wing?","TWN":"你……？不是右翼第6小隊的隊長嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"여기까지 왜 직접 오신 거예요?","JPN":"なぜここまで直接来られたんですか？","ENG":"What made you come all the way here?","TWN":"你怎麼跑到這裡來了？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"나, 나타났습니다! 놈이 나타났습니다!!","JPN":"あ、現れました！　奴が現れました！！","ENG":"H-he has revealed himself! Him!","TWN":"出，出現了！那傢伙出現了！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"마왕 네헤모트가……!","JPN":"魔王、ネヘモトが……！","ENG":"Nehemoth, the Demon Lord–!","TWN":"魔王貝赫莫特……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"저 폭발은……?","JPN":"あの爆発は……？","ENG":"An explosion...?","TWN":"那爆炸是……？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE"},{"id":"L46_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"독기가 더 강해졌다. 마왕이야.","JPN":"毒気がさらに強くなった。魔王だ。","ENG":"The poison is getting stronger. It's him.","TWN":"毒氣變得更濃了，是魔王。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"죄송합니다! 어떻게든 맞서려고 했지만……!","JPN":"申し訳ございません！　戦うことすら私たちでは……！","ENG":"I'm sorry! We tried our best, but...!","TWN":"對不起！雖然我們已經努力抵抗了……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"놈이 구원자님을 찾고 있습니다!","JPN":"奴が救世主様を探しています！","ENG":"He is looking for the Savior!","TWN":"那傢伙正在尋找救贖者大人！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"도망치십시오! 살고 싶으시다면 어서 도망치셔야 합니다!","JPN":"逃げてください！　生きるためには、早く逃げなければなりません！","ENG":"Run! If you wish to live, you must flee at all costs!","TWN":"請快逃吧！想活下來的話，就必須快點逃走！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그래서…… 무섭다는 이유로 부하들을 내팽개치고 혼자 도망쳐 왔다는 건가?","JPN":"つまり……恐ろしいという理由で、部下たちを捨て自分一人逃げてきたのか？","ENG":"So... you ran away from fear, abandoning all of your men?","TWN":"所以……因為害怕，你便丟下部下，一個人逃回來了？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"죄송합니다, 전하!","JPN":"申し訳ございません、殿下！","ENG":"Forgive me, Your Highness!","TWN":"對不起，殿下！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"도저히, 도저히 그 앞에서 검을 뽑아들 수 없었습니다……!","JPN":"到底、到底奴に向かって剣を構えることができませんでした……！","ENG":"I... I just couldn't face him on my own...!","TWN":"我，我，我在那傢伙面前實在無法拔劍……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"적 앞에서 도주한 네 행동은 전쟁이 끝난 뒤에 처벌하도록 하겠다.","JPN":"敵を前にして逃走した貴様の行動については戦争が終わったあと、処罰する。","ENG":"Your punishment for running away in front of the enemy will be held after the war ends.","TWN":"你臨陣脫逃的行為，我會在戰爭結束後再處置。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"정신 차려라, 평민! 넋 놓고 있는 동안 아깝게 잃는 목숨만 늘어난다!","JPN":"しっかりしろ、平民！　ボーっとしている間にも大切な命は減っていく！","ENG":"Get yourself together, peasant! We are going to lose more men if you keep on daydreaming!","TWN":"打起精神來，平民！在你失魂落魄的這段時間，犧牲者的數量正在白白增加！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"아, 알겠습니다!","JPN":"わ、わかりました！","ENG":"O-okay!","TWN":"啊，知道了！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"알렌! 병력들의 지휘는 너에게 맡기겠다!","JPN":"アレン！　兵力の指揮は任せる！","ENG":"Allen! You are now in charge of command!","TWN":"艾倫！兵力的指揮就交給你了！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"예, 전하. 하지만 주의하셔야 합니다.","JPN":"承知いたしました、殿下。しかし、お気をつけください。","ENG":"Yes, Your Highness. But please be careful.","TWN":"是，殿下。您一定要注意安全。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"우익에 있는 병력도 모두 역전의 용사들입니다.","JPN":"右翼の兵士たちは、皆歷戦の猛者です。","ENG":"The men in the right wing are skilled soldiers.","TWN":"右翼全都是身經百戰的勇士。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"보고조차 못하고 이렇게 겁에 질린 데에는 분명 무슨 이유가……","JPN":"報告もろくにできず、ここまで怯えていることにはきっと何か理由が……","ENG":"There must be a good reason why this man is frightened so much–","TWN":"害怕成這副樣子，其中肯定有什麼原因……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"으아아아악!!","JPN":"うわぁぁぁっ！！","ENG":"Aaaahhhhh!","TWN":"呃啊啊啊啊！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE"},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"어서 사제들을 불러! 부상자들만은 살려야 돼!","JPN":"早く司祭を呼べ！　負傷者だけは助けるんだ！","ENG":"Call the priests! We must save the injured!","TWN":"快點找祭司過來！有傷患！快救助傷患！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"커헉……! 쿨럭……!","JPN":"ガハッ……！　ゴホッ……！","ENG":"Kuh...! *Cough...!*","TWN":"咳咳……！咳咳……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"도, 도와 줘…… 제발……","JPN":"た、助けてくれ……頼む……","ENG":"H-help... Please...","TWN":"請，幫……幫幫我……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"설마 우익이 돌파당한 건가? 그 잠깐 사이에?","JPN":"まさか右翼が突破されたのか？　この一瞬の隙に？","ENG":"The right wing’s been breached... That quickly?","TWN":"難道在這麼短的時間裡……右翼被突破了嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"기사단 집결! 전투에 대비하라!","JPN":"騎士団、集結！　戦闘に備えろ！","ENG":"All knights assemble! Prepare to engage!","TWN":"騎士團集合！準備戰鬥！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_QM","text":{"KOREA":"너희들이 구원기사단인가?","JPN":"そなたらが救世騎士団なのか？","ENG":"You must be the Knights of Redemption.","TWN":"你們就是，救贖騎士團嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG"},{"id":"L31_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"마왕……!","JPN":"魔王……！","ENG":"Nehemoth...!","TWN":"魔王……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"물러서세요, 구원자님. 저 자는 너무 위험합니다.","JPN":"お下がりください、救世主様。あの者は危険すぎます。","ENG":"Step back, Savior. He is far too dangerous.","TWN":"請退後，救贖者大人。那個人太危險了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"구원자를 찾으러 왔다.","JPN":"救世主を探しに来た。","ENG":"I am here for the Savior.","TWN":"我來找救贖者。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"너희들의 구원자는 어디에 있는가. 나는 그 자를 원한다.","JPN":"そなたらの救世主はどこだ。我はその者を探している。","ENG":"Where is your Savior? I wish to see him.","TWN":"你們的救贖者在哪裡，帶我見他。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"……애석하게 됐군. 그 소원은 이루기 힘들 테니.","JPN":"……残念だったな。その願いは叶わない。","ENG":"...Too bad. Your wish will not be granted.","TWN":"……真可惜，你的願望不能實現了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"우익을 돌파한 위력은 인정해 주지.","JPN":"右翼を突破した威力だけは認めよう。","ENG":"Breaking through the right wing was not expected, I admit.","TWN":"我承認你突破右翼的實力很強。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하지만 적진 한복판에 단신으로 뛰어든 건 분명한 오판이다.","JPN":"だが、敵陣のど真ん中に単身で飛び込んだのはこの上ない判断ミスだ。","ENG":"But you have made a foolish decision, running straight into enemy territory.","TWN":"不過單槍匹馬地闖入敵營中央，這件事是你的判斷失誤。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"전 병력! 대오를 지키면서 화력을 집중하라!","JPN":"全兵力！　隊伍を崩さずに、火力を集中させろ！","ENG":"All forces! Keep your positions and fire!","TWN":"全體兵力！保持佇列的同時集中火力！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L42_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"상대는 마왕이다! 절대 접근하게 두지 마라!","JPN":"相手は魔王だ！　絶対に近づかせるな！","ENG":"The target is the Demon Lord! Do not let him approach!","TWN":"對手是魔王！絕對不能讓他靠近！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"쓸 수 있는 모든 수단을 동원해서라도, 네 놈을 쓰러뜨리겠다.","JPN":"どんな手を使ってでも、貴様を倒す。","ENG":"I will take you down, even if it means using everything in my power to do so.","TWN":"哪怕動用一切手段，我們也要打敗你。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L45_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"이건 술집에서 떠드는 영웅담 따위가 아니라…… 우리의 생존이 걸린 문제니 말이다.","JPN":"これは酒場で飛び交う武勇伝などではない……我々の生存がかかっているのだ。","ENG":"For this is not a mere tale... but a battle for our survival.","TWN":"這不是酒吧裡流傳的英雄故事……而是關乎我們生死存亡的問題。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"……그렇군.","JPN":"……なるほど。","ENG":"...I see.","TWN":"……我明白了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"그렇다면 숫자로는 격을 넘어설 수 없다는 사실을 가르쳐 주마.","JPN":"ならば、数だけでは超えられない格の差というものを教えてやろう。","ENG":"I shall teach you a lesson, then. Being outnumbered does not mean I am outclassed.","TWN":"那我就用事實告訴你們，僅憑人多是無法戰勝我的。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"}]`);export{e as default};